package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.Method;
import java.util.Arrays;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatValidateTest {

    private CSVFormat csvFormat;
    private Method validateMethod;

    @BeforeEach
    public void setUp() throws Exception {
        // Use the default CSVFormat instance as base
        csvFormat = CSVFormat.DEFAULT;

        // Access private validate method by reflection
        validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
    }

    private void invokeValidate(CSVFormat format) throws Exception {
        validateMethod.invoke(format);
    }

    @Test
    public void testValidate_validDefaultFormat() {
        assertDoesNotThrow(() -> invokeValidate(csvFormat));
    }

    @Test
    public void testValidate_delimiterIsLineBreak() throws Exception {
        CSVFormat format = csvFormat.withDelimiter('\n');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        // message contains "delimiter cannot be a line break"
    }

    @Test
    public void testValidate_delimiterEqualsQuoteCharacter() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(',').withQuote(',');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        // message contains "quoteChar character and the delimiter cannot be the same"
    }

    @Test
    public void testValidate_delimiterEqualsEscapeCharacter() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(',').withEscape(',');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        // message contains "escape character and the delimiter cannot be the same"
    }

    @Test
    public void testValidate_delimiterEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(',').withCommentMarker(',');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
    }

    @Test
    public void testValidate_quoteCharacterEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withQuote('#').withCommentMarker('#');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
    }

    @Test
    public void testValidate_escapeCharacterEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withEscape('#').withCommentMarker('#');
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
    }

    @Test
    public void testValidate_noEscapeCharacterButQuoteModeNone() throws Exception {
        CSVFormat format = csvFormat.withEscape((Character) null).withQuoteMode(QuoteMode.NONE);
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
    }

    @Test
    public void testValidate_headerContainsDuplicates() throws Exception {
        String[] duplicateHeader = new String[] {"a", "b", "a"};
        CSVFormat format = csvFormat.withHeader(duplicateHeader);
        Exception ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
    }

    @Test
    public void testValidate_headerNoDuplicates() throws Exception {
        String[] uniqueHeader = new String[] {"a", "b", "c"};
        CSVFormat format = csvFormat.withHeader(uniqueHeader);
        assertDoesNotThrow(() -> invokeValidate(format));
    }

    @Test
    public void testValidate_nullQuoteCharacterDelimiterDifferent() throws Exception {
        CSVFormat format = csvFormat.withQuote(null).withDelimiter(';').withEscape('\\').withQuoteMode(QuoteMode.ALL);
        assertDoesNotThrow(() -> invokeValidate(format));
    }

    @Test
    public void testValidate_escapeCharacterNullQuoteModeNotNone() throws Exception {
        CSVFormat format = csvFormat.withEscape(null).withQuoteMode(QuoteMode.ALL);
        assertDoesNotThrow(() -> invokeValidate(format));
    }
}
